// ── QUERY FUNCTIONS ──────────────────────────────────────────

const getAtomsBySubject = (subject) =>
  STARKY_ATOMS.filter(a => a.subject === subject);

const getAtomsByUnit = (subject, unit) =>
  STARKY_ATOMS.filter(a => a.subject === subject && a.unit === unit);

const getAtomsByDifficulty = (subject, difficulty) =>
  STARKY_ATOMS.filter(a => a.subject === subject && a.difficulty === difficulty);

const getHighWeightAtoms = (subject) =>
  STARKY_ATOMS.filter(a => a.subject === subject && a.examWeight === "high");

const getAtomById = (id) =>
  STARKY_ATOMS.find(a => a.id === id);

const getRelatedAtoms = (id) => {
  const atom = getAtomById(id);
  if (!atom) return [];
  return atom.relatedAtoms.map(rid => getAtomById(rid)).filter(Boolean);
};

